const express = require('express');
const bodyParser = require('body-parser');
const axios = require('axios'); // For proxying requests
const fs = require('fs');
const path = require('path');
const config = require('./config');

// !!! SECURITY WARNING !!!
// This implementation uses `eval()` and `require()` dynamically based on configuration
// and environment variables. This poses a significant security risk if plugin code
// can be influenced by untrusted sources. Ensure all plugin code is thoroughly
// vetted and comes from trusted origins only. Arbitrary code execution is possible.
// In a production environment, consider using `vm.Script` with a sandboxed context
// for `eval()` or strictly controlling plugin file access.

const app = express();
const loadedPlugins = {}; // Stores plugin factory functions

app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

/**
 * Loads plugins from a given file path using require().
 * @param {string} pluginPath The full path to the plugin file.
 */
function loadPluginFromFile(pluginPath) {
  try {
    const pluginName = path.basename(pluginPath, '.js');
    const plugin = require(pluginPath);
    loadedPlugins[pluginName] = plugin;
    console.log(`[Plugin Loader] Loaded file plugin: ${pluginName}`);
  } catch (error) {
    console.error(`[Plugin Loader] Error loading plugin from file ${pluginPath}:`, error.message);
  }
}

/**
 * Loads plugins from a code string using eval().
 * This function creates a isolated scope to simulate module.exports for the eval'd code.
 * @param {object} pluginConfig An object containing plugin name, code (JavaScript string), and optional options.
 */
function loadPluginFromCodeString(pluginConfig) {
  const { name, code } = pluginConfig;
  if (!name || !code) {
    console.error('[Plugin Loader] Invalid plugin config for code string. Missing name or code.');
    return;
  }
  try {
    // Create a mock 'module' and 'exports' object for the eval'd code
    const moduleWrapper = { exports: {} };

    // Eval the code in a function scope, passing 'module' and 'exports'
    // This allows the eval'd code to behave like a standard Node.js module (e.g., using module.exports = ...)
    // Note: eval() is inherently dangerous. This setup provides basic encapsulation, but no true sandboxing.
    eval(`(function(module, exports){ ${code} })(moduleWrapper, moduleWrapper.exports);`);

    loadedPlugins[name] = moduleWrapper.exports;
    console.log(`[Plugin Loader] Loaded code string plugin: ${name}`);
  } catch (error) {
    console.error(`[Plugin Loader] Error loading plugin from code string '${name}':`, error.message);
  }
}

/**
 * Initializes all plugins specified in the configuration and environment variables.
 */
function initializePlugins() {
  // 1. Load plugins from specified directories using `require()`
  if (config.pluginDirs && Array.isArray(config.pluginDirs)) {
    config.pluginDirs.forEach(dir => {
      if (fs.existsSync(dir) && fs.lstatSync(dir).isDirectory()) {
        fs.readdirSync(dir).forEach(file => {
          if (file.endsWith('.js')) {
            loadPluginFromFile(path.join(dir, file));
          }
        });
      } else {
        console.warn(`[Plugin Loader] Plugin directory not found or not a directory: ${dir}`);
      }
    });
  }

  // 2. Load plugins from environment variables using `eval()`
  const envPluginsJson = process.env.GATEWAY_PLUGINS;
  if (envPluginsJson) {
    try {
      // Assuming the environment variable is a base64 encoded JSON string
      const decodedEnvPlugins = Buffer.from(envPluginsJson, 'base64').toString('utf8');
      const pluginsFromEnv = JSON.parse(decodedEnvPlugins);

      if (Array.isArray(pluginsFromEnv)) {
        pluginsFromEnv.forEach(pluginConfig => loadPluginFromCodeString(pluginConfig));
      } else {
        console.error('[Plugin Loader] GATEWAY_PLUGINS environment variable must be a JSON array of plugin configurations.');
      }
    } catch (error) {
      console.error('[Plugin Loader] Error parsing or loading plugins from GATEWAY_PLUGINS environment variable:', error.message);
    }
  }

  console.log('[Plugin Loader] All plugins initialized. Available plugins:', Object.keys(loadedPlugins));
}

/**
 * Sets up API routes and applies plugins.
 */
function setupRoutes() {
  config.routes.forEach(route => {
    const { path, method, plugins, targetUrl } = route;

    if (!path || !method || !targetUrl) {
      console.error(`[Gateway] Invalid route configuration: Missing path, method, or targetUrl for route:`, route);
      return;
    }

    const routeMiddleware = [];

    // Apply plugins as middleware
    if (plugins && Array.isArray(plugins)) {
      plugins.forEach(pluginConfig => {
        let pluginName;
        let pluginOptions = {};

        if (typeof pluginConfig === 'string') { // Plugin specified by name string
          pluginName = pluginConfig;
        } else if (typeof pluginConfig === 'object' && pluginConfig.name) { // Plugin with options
          pluginName = pluginConfig.name;
          pluginOptions = pluginConfig.options || {};
        } else {
          console.warn(`[Gateway] Invalid plugin configuration for route ${path}:`, pluginConfig);
          return;
        }

        const pluginFactory = loadedPlugins[pluginName];
        if (pluginFactory) {
          try {
            // Call the plugin's factory function with options to get the middleware function
            const pluginInstance = pluginFactory(pluginOptions);
            if (typeof pluginInstance === 'function') {
              routeMiddleware.push(pluginInstance);
              console.log(`[Gateway] Applied plugin '${pluginName}' to route ${method.toUpperCase()} ${path}`);
            } else {
              console.error(`[Gateway] Plugin '${pluginName}' did not return a function for route ${method.toUpperCase()} ${path}.`);
            }
          } catch (e) {
            console.error(`[Gateway] Error initializing plugin '${pluginName}' for route ${method.toUpperCase()} ${path}:`, e.message);
          }
        } else {
          console.warn(`[Gateway] Plugin '${pluginName}' not found for route ${method.toUpperCase()} ${path}. Skipping.`);
        }
      });
    }

    // Add the proxy middleware as the last step in the chain
    routeMiddleware.push(async (req, res) => {
      try {
        console.log(`[Proxy] Forwarding request to: ${targetUrl}${req.originalUrl}`);

        const proxyRes = await axios({
          method: req.method,
          url: `${targetUrl}${req.originalUrl}`, // Append original URL to target
          headers: { ...req.headers, host: new URL(targetUrl).host }, // Important for target service
          data: req.body,
          params: req.query,
          validateStatus: () => true // Do not throw on 4xx/5xx responses, handle them explicitly
        });

        // Copy headers from proxy response to gateway response
        for (const key in proxyRes.headers) {
          res.set(key, proxyRes.headers[key]);
        }

        res.status(proxyRes.status).send(proxyRes.data);
      } catch (error) {
        console.error(`[Proxy] Error forwarding request to ${targetUrl}${req.originalUrl}:`, error.message);
        res.status(500).json({ error: 'Gateway proxy error', details: error.message });
      }
    });

    // Register the route with Express, applying all collected middleware
    app[method.toLowerCase()](path, ...routeMiddleware);
    console.log(`[Gateway] Registered route: ${method.toUpperCase()} ${path}`);
  });
}

// Start the gateway
async function startGateway() {
  initializePlugins(); // Load all plugins first
  setupRoutes();      // Then configure routes with loaded plugins

  app.listen(config.port, () => {
    console.log(`API Gateway running on http://localhost:${config.port}`);
  });
}

startGateway();